import React from 'react';
import { FontWeightTokens } from '@contentful/f36-tokens';
import type {
  PolymorphicComponent,
  PolymorphicProps,
  ExpandProps,
} from '@contentful/f36-core';
import { Text, type TextProps } from '../Text';
import { useDensity } from '@contentful/f36-utils';

const CAPTION_DEFAULT_TAG = 'span';

export interface CaptionInternalProps extends Omit<TextProps, 'as'> {
  children?: React.ReactNode;
  fontWeight?: Extract<
    FontWeightTokens,
    'fontWeightNormal' | 'fontWeightMedium'
  >;
  isTruncated?: boolean;
  isWordBreak?: boolean;
}

export type CaptionProps<
  E extends React.ElementType = typeof CAPTION_DEFAULT_TAG,
> = PolymorphicProps<CaptionInternalProps, E>;

function _Caption<E extends React.ElementType = typeof CAPTION_DEFAULT_TAG>(
  {
    children,
    fontWeight = 'fontWeightNormal',
    testId = 'cf-ui-caption',
    as,
    fontColor = 'gray900',
    ...otherProps
  }: CaptionProps<E>,
  ref: React.Ref<any>,
) {
  const density = useDensity();
  const Element: React.ElementType = as || CAPTION_DEFAULT_TAG;
  return (
    <Text
      as={Element}
      testId={testId}
      fontSize={density === 'high' ? 'fontSizeSHigh' : 'fontSizeS'}
      lineHeight={density === 'high' ? 'lineHeightSHigh' : 'lineHeightS'}
      fontColor={fontColor}
      fontWeight={fontWeight}
      {...otherProps}
      ref={ref}
    >
      {children}
    </Text>
  );
}

_Caption.displayName = 'Caption';

export const Caption: PolymorphicComponent<
  ExpandProps<CaptionInternalProps>,
  typeof CAPTION_DEFAULT_TAG
> = React.forwardRef(_Caption);
import React from 'react';
import tokens, {
  FontSizeTokens,
  LineHeightTokens,
  FontWeightTokens,
  FontStackTokens,
  ColorTokens,
  LetterSpacingTokens,
} from '@contentful/f36-tokens';
import { css, cx } from 'emotion';
import {
  Box,
  type PolymorphicComponent,
  type CommonProps,
  type MarginProps,
  type PolymorphicProps,
  type ExpandProps,
} from '@contentful/f36-core';

export interface TextInternalProps extends CommonProps, MarginProps {
  children?: React.ReactNode;
  fontSize?: FontSizeTokens;
  lineHeight?: LineHeightTokens;
  letterSpacing?: LetterSpacingTokens;
  fontStack?: FontStackTokens;
  fontWeight?: FontWeightTokens;
  fontColor?: ColorTokens;
  isTruncated?: boolean;
  isWordBreak?: boolean;
}

const TEXT_DEFAULT_TAG = 'span';

function truncatedStyle() {
  return css({
    overflow: 'hidden',
    textOverflow: 'ellipsis',
    whiteSpace: 'nowrap',
    maxWidth: '100%',
  });
}

function wordBreakStyle() {
  return css({
    wordBreak: 'break-word',
  });
}

export type TextProps<E extends React.ElementType = typeof TEXT_DEFAULT_TAG> =
  PolymorphicProps<TextInternalProps, E, 'color'>;

function _Text<E extends React.ElementType = typeof TEXT_DEFAULT_TAG>(
  props: TextProps<E>,
  ref: React.Ref<any>,
) {
  const {
    fontSize = 'fontSizeM',
    fontStack = 'fontStackPrimary',
    fontWeight = 'fontWeightNormal',
    fontColor = 'gray800',
    lineHeight = 'lineHeightM',
    letterSpacing = 'letterSpacingDefault',
    children,
    isTruncated,
    isWordBreak,
    as,
    className,
    margin = 'none',
    ...otherProps
  } = props;
  const Element: React.ElementType = as || TEXT_DEFAULT_TAG;

  return (
    <Box
      {...otherProps}
      as={Element}
      className={cx(
        css({
          padding: 0,
          fontFamily: tokens[fontStack],
          fontWeight: tokens[fontWeight],
          color: tokens[fontColor],
          fontSize: tokens[fontSize],
          lineHeight: tokens[lineHeight],
          letterSpacing: tokens[letterSpacing],
        }),
        isTruncated ? truncatedStyle() : null,
        isWordBreak ? wordBreakStyle() : null,
        className,
      )}
      margin={margin}
      ref={ref}
    >
      {children}
    </Box>
  );
}

_Text.displayName = 'Text';

export const Text: PolymorphicComponent<
  ExpandProps<TextInternalProps>,
  typeof TEXT_DEFAULT_TAG,
  'color'
> = React.forwardRef(_Text);
import React from 'react';
import type {
  PolymorphicComponent,
  PolymorphicProps,
  ExpandProps,
} from '@contentful/f36-core';
import { Text, type TextProps } from '../Text';
import { useDensity } from '@contentful/f36-utils';

const HEADING_DEFAULT_TAG = 'h1';

export type HeadingElement = 'h1' | 'h2' | 'h3' | 'h4' | 'h5' | 'h6';

export interface HeadingInternalProps extends Omit<TextProps, 'as'> {
  as?: HeadingElement;
  children?: React.ReactNode;
  isTruncated?: boolean;
  isWordBreak?: boolean;
}

export type HeadingProps<
  E extends React.ElementType = typeof HEADING_DEFAULT_TAG,
> = PolymorphicProps<HeadingInternalProps, E>;

function _Heading<E extends React.ElementType = typeof HEADING_DEFAULT_TAG>(
  {
    children,
    testId = 'cf-ui-heading',
    as,
    fontColor = 'gray900',
    marginBottom = 'spacingM',
    ...otherProps
  }: HeadingProps<E>,
  ref: React.Ref<any>,
) {
  const density = useDensity();
  const Element: React.ElementType = as || HEADING_DEFAULT_TAG;

  return (
    <Text
      as={Element}
      testId={testId}
      marginBottom={marginBottom}
      fontWeight="fontWeightDemiBold"
      fontColor={fontColor}
      fontSize={density === 'high' ? 'fontSizeXlHigh' : 'fontSizeXl'}
      lineHeight={density === 'high' ? 'lineHeightXlHigh' : 'lineHeightXl'}
      {...otherProps}
      ref={ref}
    >
      {children}
    </Text>
  );
}

_Heading.displayName = 'Heading';

export const Heading: PolymorphicComponent<
  ExpandProps<HeadingInternalProps>,
  typeof HEADING_DEFAULT_TAG
> = React.forwardRef(_Heading);
import React from 'react';
import type {
  PolymorphicComponent,
  PolymorphicProps,
  ExpandProps,
} from '@contentful/f36-core';
import type { HeadingElement } from '../Heading';
import { Text, type TextProps } from '../Text';
import { useDensity } from '@contentful/f36-utils';

const SUBHEADING_DEFAULT_TAG = 'h3';

export interface SubheadingInternalProps extends Omit<TextProps, 'as'> {
  children?: React.ReactNode;
  as?: HeadingElement;
  isTruncated?: boolean;
  isWordBreak?: boolean;
}

export type SubheadingProps<
  E extends React.ElementType = typeof SUBHEADING_DEFAULT_TAG,
> = PolymorphicProps<SubheadingInternalProps, E>;

function _Subheading<
  E extends React.ElementType = typeof SUBHEADING_DEFAULT_TAG,
>(
  {
    children,
    testId = 'cf-ui-subheading',
    as,
    fontColor = 'gray900',
    ...otherProps
  }: SubheadingProps<E>,
  ref: React.Ref<any>,
) {
  const density = useDensity();
  const Element: React.ElementType = as || SUBHEADING_DEFAULT_TAG;
  return (
    <Text
      as={Element}
      testId={testId}
      marginBottom="spacingM"
      fontSize={density === 'high' ? 'fontSizeLHigh' : 'fontSizeL'}
      lineHeight={density === 'high' ? 'lineHeightLHigh' : 'lineHeightL'}
      fontWeight="fontWeightDemiBold"
      fontColor={fontColor}
      {...otherProps}
      ref={ref}
    >
      {children}
    </Text>
  );
}

_Subheading.displayName = 'Subheading';

export const Subheading: PolymorphicComponent<
  ExpandProps<SubheadingInternalProps>,
  typeof SUBHEADING_DEFAULT_TAG
> = React.forwardRef(_Subheading);
import React, { useEffect } from 'react';

export interface TypographyProps {
  children?: React.ReactNode;
}

/**
 * @deprecated
 */
export const Typography = (props: TypographyProps) => {
  useEffect(() => {
    // eslint-disable-next-line no-console -- allow this warning until we refactor
    console.warn(
      'Forma 36: Typography component is deprecated. You can safely remove it from your components.',
    );
  }, []);
  return <>{props.children}</>;
};

Typography.displayName = 'Typography';
import React from 'react';
import { FontSizeTokens, LineHeightTokens } from '@contentful/f36-tokens';
import type {
  PolymorphicComponent,
  PolymorphicProps,
  ExpandProps,
} from '@contentful/f36-core';
import { Text, type TextProps } from '../Text';
import type { HeadingElement } from '../Heading';

const DISPLAY_TEXT_DEFAULT_TAG = 'h2';

export interface DisplayTextInternalProps extends Omit<TextProps, 'as'> {
  children?: React.ReactNode;
  size?: 'default' | 'large';
  as?: HeadingElement;
  isTruncated?: boolean;
  isWordBreak?: boolean;
}

export type DisplayTextProps<
  E extends React.ElementType = typeof DISPLAY_TEXT_DEFAULT_TAG,
> = PolymorphicProps<DisplayTextInternalProps, E>;

function _DisplayText<
  E extends React.ElementType = typeof DISPLAY_TEXT_DEFAULT_TAG,
>(
  {
    children,
    size = 'default',
    testId = 'cf-ui-display-text',
    as,
    fontColor = 'gray900',
    ...otherProps
  }: DisplayTextProps<E>,
  ref: React.Ref<any>,
) {
  let fontSize: FontSizeTokens = 'fontSize2Xl';
  let lineHeight: LineHeightTokens = 'lineHeightXl';

  if (size === 'large') {
    fontSize = 'fontSize3Xl';
    lineHeight = 'lineHeight3Xl';
  }
  const Element: React.ElementType = as || DISPLAY_TEXT_DEFAULT_TAG;

  return (
    <Text
      as={Element}
      testId={testId}
      marginBottom={size === 'default' ? 'spacingL' : 'spacingXl'}
      fontSize={fontSize}
      lineHeight={lineHeight}
      fontColor={fontColor}
      fontWeight="fontWeightDemiBold"
      {...otherProps}
      ref={ref}
    >
      {children}
    </Text>
  );
}

_DisplayText.displayName = 'DisplayText';

export const DisplayText: PolymorphicComponent<
  ExpandProps<DisplayTextInternalProps>,
  typeof DISPLAY_TEXT_DEFAULT_TAG
> = React.forwardRef(_DisplayText);
import React from 'react';
import tokens from '@contentful/f36-tokens';
import { css, cx } from 'emotion';
import type {
  PolymorphicComponent,
  PolymorphicProps,
  ExpandProps,
} from '@contentful/f36-core';
import type { HeadingElement } from '../Heading';
import { Text, type TextProps } from '../Text';
import { useDensity } from '@contentful/f36-utils';

const SECTION_HEADING_DEFAULT_TAG = 'h2';

export interface SectionHeadingInternalProps extends Omit<TextProps, 'as'> {
  children?: React.ReactNode;
  as?: HeadingElement;
  isTruncated?: boolean;
  isWordBreak?: boolean;
}

export type SectionHeadingProps<
  E extends React.ElementType = typeof SECTION_HEADING_DEFAULT_TAG,
> = PolymorphicProps<SectionHeadingInternalProps, E>;

function _SectionHeading<
  E extends React.ElementType = typeof SECTION_HEADING_DEFAULT_TAG,
>(
  {
    children,
    className,
    testId = 'cf-ui-section-heading',
    as,
    fontColor = 'gray600',
    marginBottom = 'spacingL',
    ...otherProps
  }: SectionHeadingProps<E>,
  ref: React.Ref<HTMLHeadingElement>,
) {
  const density = useDensity();
  const Element: React.ElementType = as || SECTION_HEADING_DEFAULT_TAG;

  return (
    <Text
      as={Element}
      testId={testId}
      marginBottom={marginBottom}
      fontWeight="fontWeightMedium"
      fontColor={fontColor}
      fontSize={density === 'high' ? 'fontSizeSHigh' : 'fontSizeS'}
      lineHeight={density === 'high' ? 'lineHeightSHigh' : 'lineHeightS'}
      className={cx(
        css({
          letterSpacing: tokens.letterSpacingDefault,
        }),
        className,
      )}
      {...otherProps}
      ref={ref}
    >
      {children}
    </Text>
  );
}

_SectionHeading.displayName = 'SectionHeading';

export const SectionHeading: PolymorphicComponent<
  ExpandProps<SectionHeadingInternalProps>,
  typeof SECTION_HEADING_DEFAULT_TAG
> = React.forwardRef(_SectionHeading);
import React from 'react';
import type { PropsWithHTMLElement, ExpandProps } from '@contentful/f36-core';
import { Text, type TextProps } from '../Text';
import { useDensity } from '@contentful/f36-utils';

export type ParagraphInternalProps = TextProps & {
  children: React.ReactNode;
  isTruncated?: boolean;
  isWordBreak?: boolean;
};

export type ParagraphProps = PropsWithHTMLElement<ParagraphInternalProps, 'p'>;

export const Paragraph = React.forwardRef<
  HTMLParagraphElement,
  ExpandProps<ParagraphProps>
>(
  (
    {
      children,
      testId = 'cf-ui-paragraph',
      marginBottom = 'spacingM',
      ...otherProps
    },
    ref,
  ) => {
    const density = useDensity();

    return (
      <Text
        as="p"
        testId={testId}
        fontSize={density === 'high' ? 'fontSizeMHigh' : 'fontSizeM'}
        lineHeight={density === 'high' ? 'lineHeightMHigh' : 'lineHeightM'}
        marginBottom={marginBottom}
        {...otherProps}
        ref={ref}
      >
        {children}
      </Text>
    );
  },
);

Paragraph.displayName = 'Paragraph';
